                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                    font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
                }
                
                .cyber-grid {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    background: 
                        linear-gradient(90deg, rgba(10, 15, 30, 0.3) 1px, transparent 1px) 0 0 / 50px 50px,
                        linear-gradient(rgba(10, 15, 30, 0.3) 1px, transparent 1px) 0 0 / 50px 50px;
                    z-index: 1;
                    animation: gridMove 40s linear infinite;
                }
                
                @keyframes gridMove {
                    0% { transform: translate(0, 0); }
                    100% { transform: translate(50px, 50px); }
                }
                
                .orb-container {
                    position: absolute;
                    width: 100%;
                    height: 100%;
                    overflow: hidden;
                    z-index: 2;
                }
                
                .glow-orb {
                    position: absolute;
                    border-radius: 50%;
                    filter: blur(60px);
                    opacity: 0.4;
                }
                
                .orb-1 {
                    width: 600px;
                    height: 600px;
                    background: radial-gradient(circle at center, #00d4ff 0%, #0072ff 70%, transparent 100%);
                    top: -300px;
                    right: -300px;
                    animation: floatOrb 25s ease-in-out infinite;
                }
                
                .orb-2 {
                    width: 500px;
                    height: 500px;
                    background: radial-gradient(circle at center, #ff0080 0%, #9d00ff 70%, transparent 100%);
                    bottom: -250px;
                    left: -250px;
                    animation: floatOrb 30s ease-in-out infinite reverse;
                }
                
                @keyframes floatOrb {
                    0%, 100% {
                        transform: translate(0, 0) scale(1);
                    }
                    33% {
                        transform: translate(100px, -100px) scale(1.1);
                    }
                    66% {
                        transform: translate(-100px, 100px) scale(0.9);
                    }
                }
                
                .login-card-wrapper {
                    position: relative;
                    z-index: 10;
                    background: rgba(10, 15, 30, 0.7);
                    backdrop-filter: blur(30px);
                    border: 1px solid rgba(0, 210, 255, 0.2);
                    border-radius: 32px;
                    padding: 60px 50px;
                    width: 100%;
                    max-width: 480px;
                    box-shadow: 
                        0 25px 100px rgba(0, 112, 255, 0.15),
                        0 0 200px rgba(0, 210, 255, 0.05),
                        inset 0 0 100px rgba(0, 210, 255, 0.05);
                    animation: cardAppear 0.8s cubic-bezier(0.4, 0, 0.2, 1);
                    overflow: hidden;
                }
                
                .login-card-wrapper::before {
                    content: '';
