                .login-btn:hover:not(:disabled) {
                    transform: translateY(-5px);
                    box-shadow: 0 25px 60px rgba(0, 112, 255, 0.4);
                }
                
                .login-btn:disabled {
                    opacity: 0.6;
                    cursor: not-allowed;
                }
                
                .security-badge {
                    text-align: center;
                    padding: 20px;
                    background: rgba(0, 212, 255, 0.05);
                    border-radius: 16px;
                    border: 1px solid rgba(0, 212, 255, 0.1);
                    color: #00d4ff;
                    font-size: 0.85rem;
                    font-weight: 600;
                    letter-spacing: 1.5px;
                    text-transform: uppercase;
                }
                
                @media (max-width: 640px) {
                    .login-card-wrapper {
                        padding: 40px 30px;
                        margin: 20px;
                        max-width: calc(100% - 40px);
                    }
                    .login-title {
                        font-size: 2.2rem;
                    }
                }
            `}</style>

            <div className="cyber-grid"></div>
            
            <div className="orb-container">
                <div className="glow-orb orb-1"></div>
                <div className="glow-orb orb-2"></div>
            </div>

            <div className="login-card-wrapper">
                <div className="login-header">
                    <div className="brand-icon">
                        <span>🔐</span>
                    </div>
                    <div className="login-title">Reset Password</div>
                    <div className="login-subtitle">Create a new secure password</div>
                </div>
                
                <form onSubmit={handleResetPassword} className="form-container">
                    {error && (
                        <div style={{
                            padding: '12px 16px',
                            backgroundColor: 'rgba(239, 68, 68, 0.1)',
                            border: '1px solid rgba(239, 68, 68, 0.3)',
                            borderRadius: '8px',
                            color: '#ff6b6b',
                            fontSize: '0.9rem',
                            marginBottom: '10px'
                        }}>
                            ⚠️ {error}
                        </div>
                    )}

                    {message && (
                        <div style={{
                            padding: '12px 16px',
                            backgroundColor: 'rgba(34, 197, 94, 0.1)',
                            border: '1px solid rgba(34, 197, 94, 0.3)',
                            borderRadius: '8px',
                            color: '#22c55e',
                            fontSize: '0.9rem',
                            marginBottom: '10px'
                        }}>
                            ✅ {message}
                        </div>
                    )}

                    <div className="input-group">
                        <label className="input-label">
                            <span>🔐</span>
                            New Password
                        </label>
                        <input 
                            type="password" 
                            className="input-field"
                            placeholder="••••••••••••" 
                            value={newPassword}
                            onChange={e => setNewPassword(e.target.value)} 
                            required 
                        />
                    </div>
                    
                    <div className="input-group">
                        <label className="input-label">
                            <span>🔒</span>
                            Confirm Password
                        </label>
                        <input 
                            type="password" 
                            className="input-field"
                            placeholder="••••••••••••" 
                            value={confirmPassword}
                            onChange={e => setConfirmPassword(e.target.value)} 
                            required 
                        />
                    </div>
                    
                    <button type="submit" className="login-btn" disabled={loading}>
                        {loading ? '⏳ Resetting...' : '✅ Reset Password'}
                    </button>
                </form>
                
                <div className="security-badge">
                    Secure Password Reset Portal
                </div>
            </div>
        </div>
    );
};

const styles = {
    loginPage: {
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: 'linear-gradient(135deg, #000814 0%, #001233 30%, #000814 100%)',
        overflow: 'hidden',
        position: 'relative',
        padding: '20px',
    },
};

export default ResetPassword;
